INSERT INTO `article` VALUES (1,'2026-07-20 09:47:18.789',NULL,NULL,NULL,'what-is-computer-science','What Is Computer Science?','Khoa học máy tính là gì?','An introduction to computer science, its fundamental concepts, and its role in understanding computation and information processing.','Giới thiệu về khoa học máy tính, các khái niệm nền tảng và vai trò của lĩnh vực này trong việc nghiên cứu tính toán và xử lý thông tin.','# What Is Computer Science? A Comprehensive Guide to the Digital Era','# Khoa Học Máy Tính Là Gì? Hướng Dẫn Toàn Diện Cho Người Bắt Đầu','[\"computer-science\", \"foundations\", \"computation\"]',8,'Darian','[\"What Is Computer Science?\", \"The Core Areas of Computer Science\", \"Computer Science and Programming\", \"Why Computer Science Matters\"]',1,'[\"computational-thinking\", \"algorithms-and-complexity\"]','https://images.unsplash.com/photo-1518770660439-4636190af475',NULL),(2,'2026-07-20 09:49:23.538',NULL,NULL,NULL,'von-neumann-architecture','The Von Neumann Architecture','Kiến trúc Von Neumann','Understand the foundational computer architecture that defines how modern computers store and process instructions and data.','Tìm hiểu kiến trúc máy tính nền tảng mô tả cách các máy tính hiện đại lưu trữ và xử lý lệnh cùng dữ liệu.','# Kiến Trúc Von Neumann: Nền Tảng Của Máy Tính Hiện Đại','# Kiến Trúc Von Neumann: Nền Tảng Của Máy Tính Hiện Đại','[\"computer-architecture\", \"von-neumann\", \"computer-science\"]',11,'Darian','[\"What Is the Von Neumann Architecture?\", \"The Central Processing Unit\", \"Memory and Storage\", \"The Instruction Cycle\", \"Limitations of the Architecture\"]',1,'[\"what-is-computer-science\", \"data-information-and-representation\"]','https://images.unsplash.com/photo-1591405351990-4726e331f141',NULL),(3,'2026-07-20 09:49:40.282',NULL,NULL,NULL,'information-theory-and-information','Information Theory and the Meaning of Information','Lý thuyết thông tin và ý nghĩa của thông tin','Explore the mathematical foundations of information, entropy, uncertainty, and efficient communication.','Khám phá nền tảng toán học của thông tin, entropy, sự không chắc chắn và truyền thông tin hiệu quả.','# Information Theory and the Meaning of Information: From Mathematics to Modern Communication','# Lý Thuyết Thông Tin Và Bản Chất Của Thông Tin: Từ Toán Học Đến Truyền Thông Hiện Đại','[\"information-theory\", \"entropy\", \"mathematics\", \"computer-science\"]',14,'Darian','[\"What Is Information?\", \"Uncertainty and Entropy\", \"Information Encoding\", \"Data Compression\", \"Applications of Information Theory\"]',1,'[\"data-information-and-representation\", \"boundaries-of-computation\"]','https://images.unsplash.com/photo-1635070041078-e363dbe005cb',NULL),(4,'2026-07-20 09:49:47.605',NULL,NULL,NULL,'formal-languages-and-automata-theory','Formal Languages and Automata Theory','Ngôn ngữ hình thức và lý thuyết ôtômát','Learn how formal languages and computational machines are used to describe, recognize, and process structured information.','Tìm hiểu cách ngôn ngữ hình thức và các mô hình máy tính được sử dụng để mô tả, nhận dạng và xử lý thông tin có cấu trúc.','...','...','[\"formal-languages\", \"automata\", \"theory\", \"computer-science\"]',16,'Darian','[\"What Are Formal Languages?\", \"Finite Automata\", \"Regular Expressions\", \"Context-Free Grammars\", \"Applications in Computer Science\"]',1,'[\"theoretical-models-of-computation\", \"algorithms-and-complexity\"]','https://images.unsplash.com/photo-1516116216624-53e697fedbea',NULL),(5,'2026-07-20 09:49:58.991',NULL,NULL,NULL,'p-versus-np-problem','The P vs NP Problem','Bài toán P và NP','An introduction to one of the most important open problems in computer science and computational complexity theory.','Giới thiệu một trong những bài toán mở quan trọng nhất trong khoa học máy tính và lý thuyết độ phức tạp tính toán.','...','...','[\"complexity-theory\", \"p-vs-np\", \"algorithms\", \"computer-science\"]',15,'Darian','[\"What Is Computational Complexity?\", \"The Class P\", \"The Class NP\", \"Why P vs NP Matters\", \"The Current State of the Problem\"]',1,'[\"algorithms-and-complexity\", \"boundaries-of-computation\"]','https://images.unsplash.com/photo-1509228468518-180dd4864904',NULL),(6,'2026-07-20 09:50:07.510',NULL,NULL,NULL,'computer-science-as-a-scientific-discipline','Computer Science as a Scientific Discipline','Khoa học máy tính với tư cách là một ngành khoa học','Examine computer science as a scientific discipline and explore how theory, experimentation, abstraction, and engineering shape the field.','Tìm hiểu khoa học máy tính với tư cách là một ngành khoa học và cách lý thuyết, thực nghiệm, trừu tượng hóa và kỹ thuật định hình lĩnh vực này.','...','...','[\"computer-science\", \"science\", \"research\", \"foundations\"]',10,'Darian','[\"Is Computer Science a Science?\", \"Theory and Abstraction\", \"Experimentation and Empirical Research\", \"The Role of Engineering\", \"The Future of Computer Science\"]',1,'[\"what-is-computer-science\", \"theoretical-models-of-computation\", \"boundaries-of-computation\"]','https://images.unsplash.com/photo-1535378917042-10a22c95931a',NULL),(7,'2026-07-20 09:52:03.942',NULL,NULL,NULL,'what-is-artificial-intelligence','What Is Artificial Intelligence?','Trí tuệ nhân tạo là gì?','An introduction to artificial intelligence, its historical foundations, core concepts, and the different ways machines can simulate intelligent behavior.','Giới thiệu về trí tuệ nhân tạo, nền tảng lịch sử, các khái niệm cốt lõi và những cách máy móc có thể mô phỏng hành vi thông minh.','...','...','[\"artificial-intelligence\", \"ai\", \"intelligent-agents\"]',10,'Darian','[\"What Is Artificial Intelligence?\", \"A Brief History of AI\", \"Strong AI and Weak AI\", \"Major Areas of Artificial Intelligence\", \"The Future of AI\"]',2,'[\"intelligent-agents\", \"history-of-artificial-intelligence\"]','https://images.unsplash.com/photo-1677442136019-21780ecad995',NULL),(8,'2026-07-20 09:52:11.730',NULL,NULL,NULL,'history-of-artificial-intelligence','The History of Artificial Intelligence','Lịch sử của trí tuệ nhân tạo','Trace the development of artificial intelligence from early symbolic systems and expert systems to modern intelligent applications.','Khám phá quá trình phát triển của trí tuệ nhân tạo từ các hệ thống ký hiệu và hệ chuyên gia ban đầu đến các ứng dụng thông minh hiện đại.','...','...','[\"artificial-intelligence\", \"ai-history\", \"expert-systems\"]',12,'Darian','[\"The Birth of Artificial Intelligence\", \"Symbolic AI\", \"The Rise of Expert Systems\", \"AI Winters\", \"The Modern AI Era\"]',2,'[\"what-is-artificial-intelligence\", \"symbolic-ai-and-knowledge-representation\"]','https://images.unsplash.com/photo-1485827404703-89b55fcc595e',NULL),(9,'2026-07-20 09:52:18.092',NULL,NULL,NULL,'intelligent-agents-and-environments','Intelligent Agents and Their Environments','Tác tử thông minh và môi trường hoạt động','Understand how intelligent agents perceive their environments, make decisions, and act to achieve specific goals.','Tìm hiểu cách các tác tử thông minh nhận thức môi trường, đưa ra quyết định và hành động để đạt được các mục tiêu cụ thể.','...','...','[\"intelligent-agents\", \"ai\", \"agent-architecture\", \"decision-making\"]',13,'Darian','[\"What Is an Intelligent Agent?\", \"Perception and Action\", \"Types of Environments\", \"Rational Agents\", \"Agent Architectures\"]',2,'[\"what-is-artificial-intelligence\", \"search-algorithms-in-ai\"]','https://images.unsplash.com/photo-1535378917042-10a22c95931a',NULL),(10,'2026-07-20 09:52:24.707',NULL,NULL,NULL,'search-algorithms-in-artificial-intelligence','Search Algorithms in Artificial Intelligence','Các thuật toán tìm kiếm trong trí tuệ nhân tạo','Explore how artificial intelligence uses search algorithms to find solutions in large and complex problem spaces.','Khám phá cách trí tuệ nhân tạo sử dụng các thuật toán tìm kiếm để tìm lời giải trong những không gian bài toán lớn và phức tạp.','...','...','[\"ai\", \"search\", \"problem-solving\", \"algorithms\"]',14,'Darian','[\"Problem-Solving as Search\", \"Breadth-First Search\", \"Depth-First Search\", \"Uniform-Cost Search\", \"Heuristic Search\"]',2,'[\"intelligent-agents-and-environments\", \"heuristic-search-and-a-star\"]','https://images.unsplash.com/photo-1551288049-bebda4e38f71',NULL),(11,'2026-07-20 09:52:29.961',NULL,NULL,NULL,'heuristic-search-and-a-star','Heuristic Search and the A* Algorithm','Tìm kiếm heuristic và thuật toán A*','Learn how heuristic functions improve search efficiency and how the A* algorithm combines actual cost with estimated cost.','Tìm hiểu cách các hàm heuristic cải thiện hiệu quả tìm kiếm và cách thuật toán A* kết hợp chi phí thực tế với chi phí ước tính.','...','...','[\"heuristic-search\", \"a-star\", \"pathfinding\", \"ai\"]',12,'Darian','[\"What Is Heuristic Search?\", \"Heuristic Functions\", \"The A* Evaluation Function\", \"Admissibility and Optimality\", \"Practical Applications\"]',2,'[\"search-algorithms-in-artificial-intelligence\", \"intelligent-agents-and-environments\"]','https://images.unsplash.com/photo-1500534623283-312aade485b7',NULL),(12,'2026-07-20 09:52:35.238',NULL,NULL,NULL,'knowledge-representation-in-artificial-intelligence','Knowledge Representation in Artificial Intelligence','Biểu diễn tri thức trong trí tuệ nhân tạo','Explore how artificial intelligence systems represent facts, concepts, relationships, and knowledge about the world.','Khám phá cách các hệ thống trí tuệ nhân tạo biểu diễn sự kiện, khái niệm, mối quan hệ và tri thức về thế giới.','...','...','[\"knowledge-representation\", \"symbolic-ai\", \"logic\", \"ai\"]',15,'Darian','[\"What Is Knowledge Representation?\", \"Logic-Based Representation\", \"Semantic Networks\", \"Knowledge Graphs\", \"Challenges in Knowledge Representation\"]',2,'[\"symbolic-ai-and-knowledge-representation\", \"expert-systems-and-rule-based-ai\"]','https://images.unsplash.com/photo-1559757175-0eb30cd8c063',NULL),(13,'2026-07-20 09:52:42.469',NULL,NULL,NULL,'symbolic-ai-and-knowledge-based-systems','Symbolic AI and Knowledge-Based Systems','AI ký hiệu và các hệ thống dựa trên tri thức','Understand the principles of symbolic artificial intelligence and how explicit rules and structured knowledge are used to solve problems.','Tìm hiểu các nguyên lý của AI ký hiệu và cách các luật rõ ràng cùng tri thức có cấu trúc được sử dụng để giải quyết vấn đề.','...','...','[\"symbolic-ai\", \"knowledge-based-systems\", \"logic\", \"expert-systems\"]',13,'Darian','[\"What Is Symbolic AI?\", \"Rules and Logic\", \"Knowledge-Based Systems\", \"Advantages and Limitations\", \"Symbolic AI Today\"]',2,'[\"knowledge-representation-in-artificial-intelligence\", \"expert-systems-and-rule-based-ai\"]','https://images.unsplash.com/photo-1516321318423-f06f85e504b3',NULL),(14,'2026-07-20 09:52:48.732',NULL,NULL,NULL,'expert-systems-and-rule-based-ai','Expert Systems and Rule-Based AI','Hệ chuyên gia và AI dựa trên luật','Learn how expert systems use domain knowledge, inference engines, and rules to make decisions and provide recommendations.','Tìm hiểu cách các hệ chuyên gia sử dụng tri thức chuyên môn, engine suy luận và các luật để đưa ra quyết định và khuyến nghị.','...','...','[\"expert-systems\", \"rule-based-ai\", \"inference\", \"artificial-intelligence\"]',11,'Darian','[\"What Is an Expert System?\", \"Knowledge Bases\", \"Inference Engines\", \"Forward and Backward Chaining\", \"Applications and Limitations\"]',2,'[\"symbolic-ai-and-knowledge-based-systems\", \"knowledge-representation-in-artificial-intelligence\"]','https://images.unsplash.com/photo-1556761175-b413da4baf72',NULL),(15,'2026-07-20 09:52:54.823',NULL,NULL,NULL,'natural-language-processing-and-language-understanding','Natural Language Processing: How Machines Understand Language','Xử lý ngôn ngữ tự nhiên: Máy tính hiểu ngôn ngữ như thế nào?','An introduction to natural language processing and the computational techniques used to analyze and understand human language.','Giới thiệu về xử lý ngôn ngữ tự nhiên và các kỹ thuật tính toán được sử dụng để phân tích và hiểu ngôn ngữ của con người.','...','...','[\"nlp\", \"natural-language-processing\", \"language\", \"ai\"]',14,'Darian','[\"What Is Natural Language Processing?\", \"Text Representation\", \"Language Understanding\", \"Common NLP Tasks\", \"The Challenges of Human Language\"]',2,'[\"what-is-artificial-intelligence\", \"knowledge-representation-in-artificial-intelligence\"]','https://images.unsplash.com/photo-1451187580459-43490279c0fa',NULL),(16,'2026-07-20 09:53:01.603',NULL,NULL,NULL,'planning-and-decision-making-in-artificial-intelligence','Planning and Decision Making in Artificial Intelligence','Lập kế hoạch và ra quyết định trong trí tuệ nhân tạo','Explore how AI systems plan sequences of actions and make decisions in environments with goals, constraints, and uncertainty.','Khám phá cách các hệ thống AI lập kế hoạch cho chuỗi hành động và đưa ra quyết định trong môi trường có mục tiêu, ràng buộc và sự không chắc chắn.','...','...','[\"ai-planning\", \"decision-making\", \"intelligent-agents\", \"artificial-intelligence\"]',13,'Darian','[\"Planning as a Search Problem\", \"Goals and Actions\", \"State-Space Planning\", \"Decision Making Under Uncertainty\", \"Applications of AI Planning\"]',2,'[\"intelligent-agents-and-environments\", \"search-algorithms-in-artificial-intelligence\", \"heuristic-search-and-a-star\"]','https://images.unsplash.com/photo-1550751827-4bd374c3f58b',NULL),(17,'2026-07-20 09:53:31.576',NULL,NULL,NULL,'what-is-machine-learning','What Is Machine Learning?','Machine Learning là gì?','An introduction to machine learning, its core concepts, learning paradigms, and relationship with artificial intelligence.','Giới thiệu về Machine Learning, các khái niệm cốt lõi, các phương pháp học và mối quan hệ với trí tuệ nhân tạo.','...','...','[\"machine-learning\", \"ai\", \"data\"]',10,'Darian','[\"What Is Machine Learning?\", \"How Machine Learning Works\", \"Types of Machine Learning\", \"Machine Learning and Artificial Intelligence\", \"The Machine Learning Workflow\"]',3,'[\"supervised-learning\", \"unsupervised-learning\"]','https://images.unsplash.com/photo-1555949963-ff9fe0c870eb',NULL),(18,'2026-07-20 09:53:37.326',NULL,NULL,NULL,'supervised-learning','Supervised Learning','Học có giám sát','Understand how supervised learning algorithms learn patterns from labeled data to make predictions and classifications.','Tìm hiểu cách các thuật toán học có giám sát học các mẫu từ dữ liệu đã được gán nhãn để đưa ra dự đoán và phân loại.','...','...','[\"supervised-learning\", \"classification\", \"regression\"]',12,'Darian','[\"What Is Supervised Learning?\", \"Labeled Data\", \"Classification\", \"Regression\", \"Common Applications\"]',3,'[\"what-is-machine-learning\", \"classification-and-regression\"]','https://images.unsplash.com/photo-1516321318423-f06f85e504b3',NULL),(19,'2026-07-20 09:53:42.428',NULL,NULL,NULL,'unsupervised-learning','Unsupervised Learning','Học không giám sát','Explore how machine learning algorithms discover hidden patterns and structures in data without predefined labels.','Khám phá cách các thuật toán Machine Learning phát hiện các mẫu và cấu trúc ẩn trong dữ liệu mà không cần nhãn được định nghĩa trước.','...','...','[\"unsupervised-learning\", \"clustering\", \"dimensionality-reduction\"]',11,'Darian','[\"What Is Unsupervised Learning?\", \"Clustering\", \"Dimensionality Reduction\", \"Discovering Hidden Patterns\", \"Applications\"]',3,'[\"what-is-machine-learning\", \"k-means-clustering\"]','https://images.unsplash.com/photo-1518186285589-2f7649de83e0',NULL),(20,'2026-07-20 09:53:47.712',NULL,NULL,NULL,'reinforcement-learning','Reinforcement Learning','Học tăng cường','Learn how agents interact with environments and improve their behavior through rewards, penalties, and trial-and-error learning.','Tìm hiểu cách các tác tử tương tác với môi trường và cải thiện hành vi thông qua phần thưởng, hình phạt và quá trình học thử-sai.','...','...','[\"reinforcement-learning\", \"agents\", \"rewards\"]',14,'Darian','[\"What Is Reinforcement Learning?\", \"Agents and Environments\", \"States and Actions\", \"Rewards and Policies\", \"Exploration and Exploitation\"]',3,'[\"what-is-machine-learning\", \"neural-networks-and-deep-learning\"]','https://images.unsplash.com/photo-1535378917042-10a22c95931a',NULL),(21,'2026-07-20 09:53:53.093',NULL,NULL,NULL,'classification-and-regression','Classification and Regression','Phân loại và hồi quy','Understand the two fundamental supervised learning tasks: predicting discrete categories and continuous numerical values.','Tìm hiểu hai bài toán nền tảng của học có giám sát: dự đoán các nhóm rời rạc và các giá trị số liên tục.','...','...','[\"classification\", \"regression\", \"supervised-learning\"]',10,'Darian','[\"Classification Problems\", \"Regression Problems\", \"Choosing the Right Task\", \"Common Algorithms\", \"Evaluating Predictions\"]',3,'[\"supervised-learning\", \"model-evaluation-and-validation\"]','https://images.unsplash.com/photo-1551288049-bebda4e38f71',NULL),(22,'2026-07-20 09:53:58.177',NULL,NULL,NULL,'linear-regression-from-first-principles','Linear Regression from First Principles','Linear Regression từ những nguyên lý cơ bản','Explore the mathematical intuition behind linear regression and how models learn relationships between variables.','Khám phá trực giác toán học phía sau Linear Regression và cách mô hình học mối quan hệ giữa các biến.','...','...','[\"linear-regression\", \"statistics\", \"supervised-learning\"]',13,'Darian','[\"The Linear Regression Problem\", \"The Linear Model\", \"Loss Functions\", \"Least Squares\", \"Model Interpretation\"]',3,'[\"classification-and-regression\", \"gradient-descent\"]','https://images.unsplash.com/photo-1635070041078-e363dbe005cb',NULL),(23,'2026-07-20 09:54:04.085',NULL,NULL,N