INSERT INTO `categories` VALUES (1,'2026-07-20 04:22:14.825',NULL,NULL,NULL,'computer-science','Cpu','Theoretical foundations, computational models, complexity theory, and core academic principles.','Computer science','cs','Các nền tảng lý thuyết, mô hình tính toán, lý thuyết độ phức tạp và các nguyên tắc học thuật cốt lõi.','Khoa học máy tính'),(2,'2026-07-20 04:23:05.235',NULL,NULL,NULL,'artificial-intelligence','Brain','Heuristic search, expert systems, agent architectures, and natural language processing techniques.','Artificial Intelligence','ai','Tìm kiếm theo phương pháp heuristic, hệ thống chuyên gia, kiến ​​trúc tác nhân và các kỹ thuật xử lý ngôn ngữ tự nhiên.','Trí tuệ nhân tạo'),(3,'2026-07-20 04:23:34.979',NULL,NULL,NULL,'machine-learning','Dna','Supervised and unsupervised learning, deep neural networks, backpropagation, and training methodologies  .','Machine Learning','ml','Học có giám sát và không giám sát, mạng nơ-ron sâu, thuật toán lan truyền ngược và các phương pháp huấn luyện.','Học máy'),(4,'2026-07-20 04:24:08.000',NULL,NULL,NULL,'software-engineering','Layers','Design principles, architectural patterns (SOLID, Clean Architecture), and software development lifecycles.','Software engineering','se','Các nguyên tắc thiết kế, mô hình kiến ​​trúc (SOLID, Clean Architecture) và vòng đời phát triển phần mềm.','Kỹ thuật phần mềm'),(5,'2026-07-20 05:42:54.521',NULL,NULL,NULL,'system-design','GitBranch','Scalability, high availability, load balancing, caching, and distributed system architectures.','System Design','sd','Khả năng mở rộng, tính sẵn sàng cao, cân bằng tải, bộ nhớ đệm và kiến ​​trúc hệ thống phân tán.','Thiết kế hệ thống'),(6,'2026-07-20 05:43:14.744',NULL,NULL,NULL,'programming','GitBranch','In-depth explorations of modern languages (TypeScript, Go, Rust) and runtime engines.','Programming','prog','Khám phá chuyên sâu về các ngôn ngữ lập trình hiện đại (TypeScript, Go, Rust) và các công cụ thực thi mã.','Lập trình'),(7,'2026-07-20 05:43:34.099',NULL,NULL,NULL,'algorithms','Binary','Search, sort, dynamic programming, graph algorithms, and asymptotic complexity analysis.','Algorithms','algo','Tìm kiếm, sắp xếp, lập trình động, thuật toán đồ thị và phân tích độ phức tạp tiệm cận.','Thuật toán'),(8,'2026-07-20 05:44:02.880',NULL,NULL,NULL,'data-structures','FolderGit','Fundamental memory structures: trees, graphs, heaps, hash tables, and advanced indexing.','Data Structures','ds','Các cấu trúc bộ nhớ cơ bản: cây, đồ thị, đống, bảng băm và lập chỉ mục nâng cao.','Cấu trúc dữ liệu'),(9,'2026-07-20 05:44:26.293',NULL,NULL,NULL,'databases','Database','Relational systems, ACID guarantees, NoSQL, distributed consistency models, and indexing strategies.','Databases','db','Các hệ thống quan hệ, đảm bảo ACID, NoSQL, mô hình nhất quán phân tán và chiến lược lập chỉ mục.','Cơ sở dữ liệu'),(10,'2026-07-20 05:44:45.886',NULL,NULL,NULL,'operating-systems','Terminal','Kernel architectures, process scheduling, memory management, virtual memory, and I/O systems.','Operating Systems','os','Kiến trúc nhân hệ điều hành, lập lịch tiến trình, quản lý bộ nhớ, bộ nhớ ảo và hệ thống I/O.','Hệ điều hành'),(11,'2026-07-20 05:45:13.642',NULL,NULL,NULL,'networking','Globe','TCP/IP stack, socket programming, application protocols, routing algorithms, and network security.','Networking','net','Ngăn xếp TCP/IP, lập trình socket, giao thức ứng dụng, thuật toán định tuyến và bảo mật mạng.','Mạng'),(12,'2026-07-20 05:45:34.826',NULL,NULL,NULL,'english-learning','Languages','Linguistic techniques, professional technical writing, and communication strategies for global SWEs.','English Learning','eng','Các kỹ thuật ngôn ngữ, viết báo cáo kỹ thuật chuyên nghiệp và chiến lược giao tiếp dành cho kỹ sư phần mềm toàn cầu.','Tiếng anh'),(13,'2026-07-20 05:45:51.916',NULL,NULL,NULL,'research','BookOpen','Academic writing, literature review methods, thesis structures, and rigorous research methodologies.','Research','res','Viết luận học thuật, phương pháp tổng quan tài liệu, cấu trúc luận văn và phương pháp nghiên cứu nghiêm túc.','Nghiên cứu'),(14,'2026-07-20 05:46:09.690','2026-07-20 06:52:22.048',NULL,NULL,'career','Briefcase','Insights on tech leadership, mentoring, interview prep, and navigating the software engineering career ladder.','Career','car','Những hiểu biết sâu sắc về kỹ năng lãnh đạo trong lĩnh vực công nghệ, cố vấn, chuẩn bị phỏng vấn và định hướng con đường sự nghiệp kỹ sư phần mềm.','Sự nghiệp');
/*!40000 ALTER TABLE `categories` ENABLE KEYS */;
